 ('3783a0ad-af15-575e-9936-d2c48102d6b3','7fd189c5-bce8-5dd5-a554-f792676236f7',1,$p$Concesivos: não obstante, conquanto, malgrado$p$,$p$Concesivos: não obstante, conquanto, malgrado$p$,'lesson',15),
 ('33973a3b-e067-576a-b7e3-b5eee4a43e92','7fd189c5-bce8-5dd5-a554-f792676236f7',2,$p$Causales y aditivos: porquanto, outrossim$p$,$p$Causales y aditivos: porquanto, outrossim$p$,'lesson',15),
 ('1843eceb-ab73-5563-8aeb-ae16f75d7877','7fd189c5-bce8-5dd5-a554-f792676236f7',3,$p$Consecutivos y adversativos: por conseguinte, todavia$p$,$p$Consecutivos y adversativos: por conseguinte, todavia$p$,'lesson',15),
 ('0ba01fe4-f82d-5945-9a0e-91e0d28ac348','7fd189c5-bce8-5dd5-a554-f792676236f7',4,$p$Estructuras: conquanto + subjuntivo, não obstante + sustantivo$p$,$p$Estructuras: conquanto + subjuntivo, não obstante + sustantivo$p$,'lesson',15),
 ('4e15a084-cf66-570f-81b7-c01313bddd2d','7fd189c5-bce8-5dd5-a554-f792676236f7',5,$p$🏁 Checkpoint Unidade 26$p$,$p$Demuestra que argumentas a nivel C1 en portugués: usas conectivos concesivos (não obstante, conquanto + subjuntivo, malgrado), causales (porquanto, visto que), aditivos formales (outrossim, ademais), consecutivos (por conseguinte, destarte) y adversativos (todavia, contudo), sin confundir «todavia» (=sin embargo) con el español «todavía».$p$,'checkpoint',40)
