('7f444109-bc4b-5145-a96f-1b97a9949cba'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'C1','writing','cloze',$p$Completa con la mesóclise de «fará» (futuro de «fazer» + «se»): «O anúncio oficial ___ amanhã pela manhã.»$p$,$j${"text": "O anúncio oficial ___ amanhã pela manhã."}$j$::jsonb,$j${"value": "far-se-á", "accepted": ["far-se-á", "far-se-a"]}$j$::jsonb,0.84,ARRAY[$p$unidad27$p$, $p$mesoclise_cloze$p$, $p$writing$p$]),
