 ('df0ee615-b78f-554d-a53f-58e7c4e3f78d','2d42ebb6-3e74-55cb-b4b2-363c211568d4',1,$p$Modismos frecuentes y su sentido (I)$p$,$p$Modismos frecuentes y su sentido (I)$p$,'lesson',15),
 ('8e53c1a2-836c-5a74-8182-0fc57723f8d0','2d42ebb6-3e74-55cb-b4b2-363c211568d4',2,$p$Modismos frecuentes y su sentido (II)$p$,$p$Modismos frecuentes y su sentido (II)$p$,'lesson',15),
 ('b4e8dbc6-c2d1-545a-8861-5a944751e7d8','2d42ebb6-3e74-55cb-b4b2-363c211568d4',3,$p$Registro: formal frente a neutro$p$,$p$Registro: formal frente a neutro$p$,'lesson',15),
