 ('92c816c0-1d94-5380-8886-c7bf5a0ba26f','20000000-0000-0000-0000-000000000002','C1',29,$p$Hipótesis y modalidad avanzada: subjuntivo y suposición$p$,'#7D3C98','psychology_alt')
insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('9d311657-d6be-5606-ab08-d4ab55b1b995','92c816c0-1d94-5380-8886-c7bf5a0ba26f',1,$p$Futuro del subjuntivo (quando eu tiver, se precisares)$p$,$p$Futuro del subjuntivo (quando eu tiver, se precisares)$p$,'lesson',15),
 ('2f8abaf0-64e2-5876-88bc-4fe19da798ba','92c816c0-1d94-5380-8886-c7bf5a0ba26f',2,$p$Período hipotético (tres tipos) y futuro do pretérito$p$,$p$Período hipotético (tres tipos) y futuro do pretérito$p$,'lesson',15),
 ('09a9e71a-2e20-56dd-b1e2-2f82f699fe9a','92c816c0-1d94-5380-8886-c7bf5a0ba26f',3,$p$Modalización: deve estar, futuro do pretérito de rumor$p$,$p$Modalización: deve estar, futuro do pretérito de rumor$p$,'lesson',15),
 ('b8615f26-26df-519d-b843-a5acf2df8e6a','92c816c0-1d94-5380-8886-c7bf5a0ba26f',4,$p$Estilo indirecto y subjuntivo en subordinadas$p$,$p$Estilo indirecto y subjuntivo en subordinadas$p$,'lesson',15),
 ('615a6b99-15b6-5dd1-a209-a291475b8061','92c816c0-1d94-5380-8886-c7bf5a0ba26f',5,$p$🏁 Checkpoint Unidade 29$p$,$p$Demuestra que manejas la modalidad a nivel C1 en portugués: usas el futuro del subjuntivo (quando eu tiver/for), el período hipotético en sus tres tipos (se chover → futuro; se tivesse → futuro do pretérito; se tivesse estudado → teria passado), la modalización (deve estar, futuro do pretérito de rumor: estaria) y la concordancia de tiempos en el estilo indirecto.$p$,'checkpoint',40)
